mapper.select:
select r.id, r.member_id as member_id, m.nickname as member_nickname, m.email as member_email, r.report_id as report_id, r.restriction_type as restriction_type, r.reason, r.status, r.previous_member_status as previous_member_status, r.start_datetime as start_datetime, r.end_datetime as end_datetime, r.released_datetime as released_datetime, r.created_datetime as created_datetime from tbl_member_restriction r join tbl_member m on r.member_id = m.id
and ( m.nickname ilike '%' || #{keyword} || '%' or m.email ilike '%' || #{keyword} || '%' )
and r.restriction_type = #{restrictionType}
and r.status = #{status}
order by r.created_datetime desc limit #{size} offset (#{page} - 1) * #{size}
